const MEYVCAnimations={prefersReducedMotion:function(){return window.matchMedia("(prefers-reduced-motion: reduce)").matches},animateIn:function(e,n="fade",i){if(this.prefersReducedMotion())return e.style.opacity="1",void(i&&i());e.classList.add("meyvc-animating",`meyvc-animate-in--${n}`);const t=()=>{e.classList.remove("meyvc-animating",`meyvc-animate-in--${n}`),e.removeEventListener("animationend",t),i&&i()};e.addEventListener("animationend",t)},animateOut:function(e,n="fade",i){if(this.prefersReducedMotion())return e.style.opacity="0",void(i&&i());e.classList.add("meyvc-animating",`meyvc-animate-out--${n}`);const t=()=>{e.classList.remove("meyvc-animating",`meyvc-animate-out--${n}`),e.removeEventListener("animationend",t),i&&i()};e.addEventListener("animationend",t)}};window.MEYVCAnimations=MEYVCAnimations;